/**
 * @summary List processed records for an ingestion job
 */
export const getListIngestionRecordsUrl = (
  id: number,
  params?: ListIngestionRecordsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/ingestion-jobs/${id}/records?${stringifiedParams}`
    : `/api/ingestion-jobs/${id}/records`;
};

